import math

def solve(co, valve_type, hr, ft, delta_p):
    # Step 1: compute_valve_area
    # Determine the constant K based on valve_type
    if valve_type in ['aortic', 'tricuspid', 'pulmonic']:
        K = 44.3
    elif valve_type == 'mitral':
        K = 37.7
    else:
        raise ValueError(f"Invalid valve_type: {valve_type}. Allowed: 'aortic', 'mitral', 'tricuspid', 'pulmonic'.")

    # Calculate valve area using the Gorlin formula: VA = CO / (K * HR * FT * sqrt(delta_P))
    va = co / (K * hr * ft * math.sqrt(delta_p))

    yield {
        "step_name": "compute_valve_area",
        "step_description": "Calculate the valve area using the Gorlin formula: VA = CO / (K * HR * FT * sqrt(delta_P)). The constant K depends on the valve type.",
        "step_result": va,
        "unit": "cm^2"
    }

    return va
